class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      show: true,
    };
  }

  c = () => {
    this.setState({
      show: false,
    });
  };
  render() {
    return (
      <div>
        {this.state.show && <EEE />}
        <button onClick={this.c}>\u70B9\u51FB</button>
      </div>
    );
  }
}

export default App;
