const P = new fn();

(Object.getPrototypeOf(P) === P.__proto__) === fn.prototype;

fn.prototype.constructor === fn; // true

// \u51FD\u6570\uFF08\u5305\u62EC\u539F\u751F\u6784\u9020\u51FD\u6570\uFF09\u7684\u539F\u578B\u5BF9\u8C61\u4E3AFunction.prototype
