function getProperty(obj, propName) {
  // \u5728\u5BF9\u8C61\u672C\u8EAB\u67E5\u627E
  if (obj.hasOwnProperty(propName)) {
    return obj[propName];
  } else if (obj.__proto__ !== null) {
    // \u5982\u679C\u5BF9\u8C61\u6709\u539F\u578B\uFF0C\u5219\u5728\u539F\u578B\u4E0A\u9012\u5F52\u67E5\u627E
    return getProperty(obj.__proto__, propName);
  } else {
    // \u76F4\u5230\u627E\u5230Object.prototype\uFF0CObject.prototype.__proto__\u4E3Anull\uFF0C\u8FD4\u56DEundefined
    return undefined;
  }
}

