   \u8DF3\u51FApromise\uFF0C\u5F80\u4E0B\u6267\u884C\uFF0C\u78B0\u5230promise.then\u8FD9\u4E2A\u5FAE\u4EFB\u52A1\uFF0C\u5C06\u5176\u52A0\u5165\u5FAE\u4EFB\u52A1\u961F\u5217
