let myWorker = new SharedWorker('worker.js');
// page\u901A\u8FC7worker port\u53D1\u9001\u6D88\u606F
myWorker.port.postMessage('\u54FC\u54FC');
// page\u901A\u8FC7worker port\u63A5\u6536\u6D88\u606F
myWorker.port.onmessage = (e) => console.log(e.data);

// worker.js
onconnect = function (e) {
  const port = e.ports[0];
  port.postMessage('\u54C8\u563F');
  port.onmessage = (e) => {
    console.log(e.data);
  };
};
