const deps = {
  \u91C7\u8D2D\u90E8: [1, 2, 3],
  \u4EBA\u4E8B\u90E8: [5, 8, 12],
  \u884C\u653F\u90E8: [5, 14, 79],
  \u8FD0\u8F93\u90E8: [3, 64, 105],
};
let member = Object.values(deps).flat(Infinity);

