function stopPropagation(e) {
  if (typeof e.stopPropagation === 'function') {
    e.stopPropagation();
  } else {
    // \u517C\u5BB9ie
    e.cancelBubble = true;
  }
}

/**
 * \u963B\u6B62\u9ED8\u8BA4\u4E8B\u4EF6
 */

function preventDefault(e) {
  if (typeof e.preventDefault === 'function') {
    e.preventDefault();
  } else {
    // \u517C\u5BB9ie
    e.returnValue = false;
  }
}
